-- ==================== 经文数据（新旧约抽样） ====================
-- 旧约 - 创世记 1章
INSERT INTO bible_verses (id, version_id, book_id, chapter_number, verse_number, verse_text) VALUES
('00000000-0000-0000-0002-000000000001', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000001', 1, 1, '起初，神创造天地。'),
('00000000-0000-0000-0002-000000000002', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000001', 1, 2, '地是空虚混沌，渊面黑暗；神的灵运行在水面上。'),
('00000000-0000-0000-0002-000000000003', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000001', 1, 3, '神说：「要有光」，就有了光。'),
('00000000-0000-0000-0002-000000000004', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000001', 1, 4, '神看光是好的，就把光暗分开了。'),
('00000000-0000-0000-0002-000000000005', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000001', 1, 5, '神称光为昼，称暗为夜。有晚上，有早晨，这是头一日。'),
-- 创世记 2章
('00000000-0000-0000-0002-000000000006', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000001', 2, 1, '天地万物都造齐了。'),
('00000000-0000-0000-0002-000000000007', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000001', 2, 2, '到第七日，神造物的工已经完毕，就在第七日歇了他一切的工，安息了。'),
('00000000-0000-0000-0002-000000000008', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000001', 2, 3, '神赐福给第七日，定为圣日，因为在这日神歇了他一切创造的工，就安息了。'),
-- 旧约 - 出埃及记 20章（十诫）
('00000000-0000-0000-0002-000000000009', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000002', 20, 1, '神吩咐这一切的话，说：'),
('00000000-0000-0000-0002-000000000010', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000002', 20, 2, '「我是耶和华你的神，曾将你从埃及地为奴之家领出来。」'),
('00000000-0000-0000-0002-000000000011', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000002', 20, 3, '「除了我以外，你不可有别的神。」'),
('00000000-0000-0000-0002-000000000012', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000002', 20, 4, '「不可为自己雕刻偶像，也不可作什么形像仿佛上天、下地和地底下、水中的百物。」'),
('00000000-0000-0000-0002-000000000013', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000002', 20, 8, '「当记念安息日，守为圣日。」'),
('00000000-0000-0000-0002-000000000014', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000002', 20, 12, '「当孝敬父母，使你的日子在耶和华你神所赐你的地上得以长久。」'),
('00000000-0000-0000-0002-000000000015', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000002', 20, 13, '「不可杀人。」'),
('00000000-0000-0000-0002-000000000016', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000002', 20, 14, '「不可奸淫。」'),
('00000000-0000-0000-0002-000000000017', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000002', 20, 15, '「不可偷盗。」'),
('00000000-0000-0000-0002-000000000018', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000002', 20, 16, '「不可作假见证陷害人。」'),
-- 出埃及记 20章 补全缺失经文
('00000000-0000-0000-0002-000000000166', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000002', 20, 5, '「不可跪拜那些像，也不可侍奉它，因为我耶和华你的神是忌邪的神。恨我的，我必追讨他的罪，自父及子，直到三四代；'),
('00000000-0000-0000-0002-000000000167', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000002', 20, 6, '「爱我、守我诫命的，我必向他们发慈爱，直到千代。」'),
('00000000-0000-0000-0002-000000000168', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000002', 20, 7, '「不可妄称耶和华你神的名，因为妄称耶和华名的，耶和华必不以他为无罪。」'),
('00000000-0000-0000-0002-000000000169', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000002', 20, 9, '「六日要劳碌作你一切的工，'),
('00000000-0000-0000-0002-000000000170', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000002', 20, 10, '「但第七日是向耶和华你神当守的安息日。这一日你和你的儿女、仆婢、牲畜，并你城里寄居的客旅，无论何工都不可作，'),
('00000000-0000-0000-0002-000000000171', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000002', 20, 11, '「因为六日之内，耶和华造天、地、海和其中的万物，第七日便安息，所以耶和华赐福与安息日，定为圣日。」'),
('00000000-0000-0000-0002-000000000172', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000002', 20, 17, '「不可贪恋人的房屋，也不可贪恋人的妻子、仆婢、牛驴，并他一切所有的。」'),
-- 以赛亚书 40章 补全经文
('00000000-0000-0000-0002-000000000173', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000023', 40, 25, '那圣者说：「你们将谁比我，叫他与我相等呢？」'),
('00000000-0000-0000-0002-000000000174', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000023', 40, 26, '你们向上举目，看谁创造这万象，按数目领出，他一一称其名，因他的权能，又因他的大能大力，连一个都不缺。'),
('00000000-0000-0000-0002-000000000175', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000023', 40, 27, '雅各啊，你为何说：「我的道路向耶和华隐藏？」以色列啊，你为何言：「我的冤屈神并不查问？」'),
('00000000-0000-0000-0002-000000000176', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000023', 40, 32, '但那等候耶和华的，必从新得力。他们必如鹰展翅上腾，他们奔跑却不困倦，行走却不疲乏。'),
-- 旧约 - 申命记 6章
('00000000-0000-0000-0002-000000000019', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000005', 6, 4, '「以色列啊，你要听！耶和华我们神是独一的主。'),
('00000000-0000-0000-0002-000000000020', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000005', 6, 5, '你要尽心、尽性、尽力爱耶和华你的神。'),
('00000000-0000-0000-0002-000000000021', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000005', 6, 6, '我今日所吩咐你的话都要记在心上，'),
('00000000-0000-0000-0002-000000000022', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000005', 6, 7, '也要殷勤教训你的儿女，无论你坐在家里，行在路上，躺下，起来，都要谈论。'),
-- 旧约 - 诗篇 1章
('00000000-0000-0000-0002-000000000023', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 1, 1, '不从恶人的计谋，不站罪人的道路，不坐亵慢人的座位，'),
('00000000-0000-0000-0002-000000000024', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 1, 2, '惟喜爱耶和华的律法，昼夜思想，这人便为有福。'),
('00000000-0000-0000-0002-000000000025', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 1, 3, '他要像一棵树栽在溪水旁，按时候结果子，叶子也不枯干。凡他所作的尽都顺利。'),
-- 诗篇 23章
('00000000-0000-0000-0002-000000000026', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 23, 1, '耶和华是我的牧者，我必不至缺乏。'),
('00000000-0000-0000-0002-000000000027', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 23, 2, '他使我躺卧在青草地上，领我在可安歇的水边。'),
('00000000-0000-0000-0002-000000000028', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 23, 3, '他使我的灵魂苏醒，为自己的名引导我走义路。'),
('00000000-0000-0000-0002-000000000029', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 23, 4, '我虽然行过死荫的幽谷，也不怕遭害，因为你与我同在；你的杖，你的竿，都安慰我。'),
('00000000-0000-0000-0002-000000000030', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 23, 5, '在我敌人面前，你为我摆设筵席；你用油膏了我的头，使我的福杯满溢。'),
('00000000-0000-0000-0002-000000000031', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 23, 6, '我一生一世必有恩惠慈爱随着我；我且要住在耶和华的殿中，直到永远。'),
-- 诗篇 121章
('00000000-0000-0000-0002-000000000032', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 121, 1, '我要向山举目，我的帮助从何而来？'),
('00000000-0000-0000-0002-000000000033', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 121, 2, '我的帮助从造天地的耶和华而来。'),
('00000000-0000-0000-0002-000000000034', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 121, 3, '他必不叫你的脚摇动，保护你的必不打盹。'),
('00000000-0000-0000-0002-000000000035', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 121, 4, '保护以色列的，也不打盹也不睡觉。'),
('00000000-0000-0000-0002-000000000036', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 121, 5, '保护你的是耶和华，耶和华在你右边荫庇你。'),
('00000000-0000-0000-0002-000000000037', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 121, 6, '白日，太阳必不伤你；夜间，月亮必不害你。'),
('00000000-0000-0000-0002-000000000038', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 121, 7, '耶和华要保护你，免受一切的灾害。他要保护你的性命。'),
('00000000-0000-0000-0002-000000000039', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 121, 8, '你出你入，耶和华要保护你，从今时直到永远。'),
-- 旧约 - 箴言 3章
('00000000-0000-0000-0002-000000000040', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000020', 3, 5, '你要专心仰赖耶和华，不可倚靠自己的聪明，'),
('00000000-0000-0000-0002-000000000041', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000020', 3, 6, '在你一切所行的事上都要认定他，他必指引你的路。'),
('00000000-0000-0000-0002-000000000042', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000020', 3, 7, '不要自以为有智慧，要敬畏耶和华，远离恶事。'),
('00000000-0000-0000-0002-000000000043', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000020', 3, 8, '这便医治你的肚脐，滋润你的百骨。'),
-- 箴言 9章
('00000000-0000-0000-0002-000000000044', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000020', 9, 10, '敬畏耶和华是智慧的开端，认识至圣者便是聪明。'),
-- 旧约 - 以赛亚书 40章
('00000000-0000-0000-0002-000000000045', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000023', 40, 28, '你岂不曾知道吗？你岂不曾听见吗？永在的神耶和华，创造地极的主，并不疲乏，也不困倦，他的智慧无法测度。'),
('00000000-0000-0000-0002-000000000046', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000023', 40, 29, '疲乏的，他赐能力；软弱的，他加力量。'),
('00000000-0000-0000-0002-000000000047', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000023', 40, 30, '就是少年人也要疲乏困倦，强壮的也必全然跌倒；'),
('00000000-0000-0000-0002-000000000048', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000023', 40, 31, '但那等候耶和华的，必从新得力。他们必如鹰展翅上腾，他们奔跑却不困倦，行走却不疲乏。'),
-- 以赛亚书 43章
('00000000-0000-0000-0002-000000000049', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000023', 43, 1, '雅各啊，创造你的耶和华；以色列啊，造成你的那位，现在如此说：「你不要害怕，因为我救赎了你。我曾提你的名召你，你是属我的。'),
('00000000-0000-0000-0002-000000000050', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000023', 43, 2, '你从水中经过，我必与你同在；你趟过江河，水必不漫过你；你从火中行过，必不被烧，火焰也不着在你身上。'),
('00000000-0000-0000-0002-000000000051', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000023', 43, 3, '因为我是耶和华你的神，是以色列的圣者你的救主。'),
-- 旧约 - 耶利米书 29章
('00000000-0000-0000-0002-000000000052', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000024', 29, 11, '耶和华说：我知道我向你们所怀的意念，是赐平安的意念，不是降灾祸的意念，要叫你们末后有指望。'),
('00000000-0000-0000-0002-000000000053', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000024', 29, 12, '你们要呼求我，祷告我，我就应允你们。'),
('00000000-0000-0000-0002-000000000054', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000024', 29, 13, '你们寻求我，若专心寻求我，就必寻见。'),
-- 诗篇 19章（大卫的诗，述说神的荣耀）
('00000000-0000-0000-0002-000000000105', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 19, 1, '诸天述说神的荣耀，穹苍传扬他的手段。'),
('00000000-0000-0000-0002-000000000106', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 19, 2, '这日到那日发出言语，这夜到那夜传出知识。'),
('00000000-0000-0000-0002-000000000107', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 19, 3, '无言无语，也无声音可听。'),
('00000000-0000-0000-0002-000000000108', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 19, 4, '他的量带通遍天下，他的言语传到地极。神在其间为太阳安设帐幕。'),
('00000000-0000-0000-0002-000000000109', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 19, 5, '太阳如同新郎出洞房，又如勇士欢然奔路。'),
('00000000-0000-0000-0002-000000000110', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 19, 7, '耶和华的律法全备，能苏醒人心；耶和华的法度确定，能使愚人有智慧。'),
('00000000-0000-0000-0002-000000000111', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 19, 8, '耶和华的训词正直，能快活人心；耶和华的命令清洁，能明亮人的眼目。'),
('00000000-0000-0000-0002-000000000112', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 19, 14, '耶和华我的磐石，我的救赎主啊，愿我口中的言语，心里的意念，在你面前蒙悦纳。'),
-- 诗篇 34章（大卫的诗，称颂神的救恩）
('00000000-0000-0000-0002-000000000113', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 34, 1, '我要时时称颂耶和华，赞美他的话必常在我口中。'),
('00000000-0000-0000-0002-000000000114', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 34, 2, '我的心必因耶和华夸耀；谦卑人听见，就要喜乐。'),
('00000000-0000-0000-0002-000000000115', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 34, 3, '你们和我当称耶和华为大，一同高举他的名。'),
('00000000-0000-0000-0002-000000000116', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 34, 4, '我曾寻求耶和华，他就应允我，救我脱离了一切的恐惧。'),
('00000000-0000-0000-0002-000000000117', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 34, 5, '凡仰望他的，便有光荣；他们的脸，必不蒙羞。'),
('00000000-0000-0000-0002-000000000118', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 34, 6, '我这困苦人呼求，耶和华便垂听，救我脱离一切患难。'),
('00000000-0000-0000-0002-000000000119', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 34, 7, '耶和华的使者，在敬畏他的人四围安营搭救他们。'),
('00000000-0000-0000-0002-000000000120', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 34, 8, '你们要尝尝主恩的滋味，便知道他是美善；投靠他的人有福了！'),
('00000000-0000-0000-0002-000000000121', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 34, 9, '耶和华的圣民哪，你们当敬畏他，因敬畏他的一无所缺。'),
('00000000-0000-0000-0002-000000000122', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 34, 10, '少壮狮子还缺食忍饿；但寻求耶和华的，什么好处都不缺。'),
('00000000-0000-0000-0002-000000000123', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 34, 11, '众弟子啊，你们当来听我的话！我要将敬畏耶和华的道教训你们。'),
('00000000-0000-0000-0002-000000000124', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 34, 12, '有何人喜好存活，爱慕长寿，得享美福，'),
('00000000-0000-0000-0002-000000000125', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 34, 13, '就要禁止舌头不出恶言，嘴唇不说诡诈的话。'),
('00000000-0000-0000-0002-000000000126', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 34, 14, '要离恶行善，寻求和睦，一心追赶。'),
('00000000-0000-0000-0002-000000000127', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 34, 15, '耶和华的眼目看顾义人，他的耳朵听他们的呼求。'),
('00000000-0000-0000-0002-000000000128', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 34, 17, '义人呼求，耶和华听见了，便救他们脱离一切患难。'),
('00000000-0000-0000-0002-000000000129', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 34, 18, '耶和华靠近伤心的人，拯救灵性痛悔的人。'),
('00000000-0000-0000-0002-000000000130', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 34, 19, '义人多有苦难，但耶和华救他脱离这一切。'),
-- 诗篇 139章（大卫的诗，神无所不知）
('00000000-0000-0000-0002-000000000131', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 1, '耶和华啊，你已经鉴察我，认识我。'),
('00000000-0000-0000-0002-000000000132', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 2, '我坐下，我起来，你都晓得，你从远处知道我的意念。'),
('00000000-0000-0000-0002-000000000133', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 3, '我行路，我躺卧，你都细察，你也深知我一切所行的。'),
('00000000-0000-0000-0002-000000000134', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 4, '耶和华啊，我舌头上的话，你没有一句不知道的。'),
('00000000-0000-0000-0002-000000000135', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 5, '你在我前后环绕我，按手在我身上。'),
('00000000-0000-0000-0002-000000000136', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 6, '这样的知识奇妙，是我不能测的；至高，是我不能及的。'),
('00000000-0000-0000-0002-000000000137', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 7, '我往哪里去躲避你的灵？我往哪里逃躲避你的面？'),
('00000000-0000-0000-0002-000000000138', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 8, '我若升到天上，你在那里；我若在阴间下榻，你也在那里。'),
('00000000-0000-0000-0002-000000000139', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 9, '我若展开清晨的翅膀，飞到海极居住，'),
('00000000-0000-0000-0002-000000000140', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 10, '就是在那里，你的手必引导我，你的右手也必扶持我。'),
('00000000-0000-0000-0002-000000000141', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 14, '我要称谢你，因我受造奇妙可畏。你的作为奇妙，这是我心深知道的。'),
('00000000-0000-0000-0002-000000000142', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 23, '神啊，求你鉴察我，知道我的心思；试炼我，知道我的意念，'),
('00000000-0000-0000-0002-000000000143', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 24, '看在我里面有什么恶行没有，引导我走永生的道路。'),
-- 诗篇 1章 补全
('00000000-0000-0000-0002-000000000144', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 1, 4, '恶人并不是这样，乃像糠秕被风吹散。'),
('00000000-0000-0000-0002-000000000145', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 1, 5, '因此当审判的时候，恶人必站立不住；罪人在义人的会中也是如此。'),
('00000000-0000-0000-0002-000000000146', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 1, 6, '因为耶和华知道义人的道路，恶人的道路却必灭亡。'),
-- 诗篇 19章 补全缺失经文
('00000000-0000-0000-0002-000000000147', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 19, 6, '它从天这边出来，绕到天那边，没有一物被隐藏不得它的热气。'),
('00000000-0000-0000-0002-000000000148', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 19, 9, '耶和华的道理洁净，存到永远；耶和华的典章真实，全然公义。'),
('00000000-0000-0000-0002-000000000149', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 19, 10, '都比金子可羡慕，且比极多的精金可羡慕；比蜜甘甜，且比蜂房下滴的蜜甘甜。'),
('00000000-0000-0000-0002-000000000150', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 19, 11, '况且你的仆人因此受警戒，守着这些便有大赏。'),
('00000000-0000-0000-0002-000000000151', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 19, 12, '谁能知道自己的错失呢？愿你赦免我隐而未现的过错。'),
('00000000-0000-0000-0002-000000000152', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 19, 13, '求你拦阻仆人不犯任意妄为的罪，不容这罪辖制我，我便完全，免犯大罪。'),
-- 诗篇 34章 补全缺失经文
('00000000-0000-0000-0002-000000000153', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 34, 16, '耶和华向行恶的人变脸，要从世上除灭他们的名号。'),
('00000000-0000-0000-0002-000000000154', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 34, 20, '又保全他一身的骨头，连一根也不折断。'),
-- 诗篇 139章 补全缺失经文
('00000000-0000-0000-0002-000000000155', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 11, '我若说："黑暗必定遮蔽我，我周围的亮光必成为黑夜"，'),
('00000000-0000-0000-0002-000000000156', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 12, '黑暗也不能遮蔽我使你不见，黑夜却如白昼发亮。黑暗和光明，在你看都是一样。'),
('00000000-0000-0000-0002-000000000157', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 13, '我的肺腑是你所造的，我在母腹中，你已覆庇我。'),
('00000000-0000-0000-0002-000000000158', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 15, '我在暗中受造，在地的深处被联络，那时，我的形体并不向你隐藏。'),
('00000000-0000-0000-0002-000000000159', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 16, '我未成形的体质，你的眼早已看见了。你所定的日子，我尚未度一日，你都写在你的册上了。'),
('00000000-0000-0000-0002-000000000160', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 17, '神啊，你的意念向我何等宝贵！其数何等众多！'),
('00000000-0000-0000-0002-000000000161', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 18, '我若数点，比海沙更多。我睡醒的时候，仍和你同在。'),
('00000000-0000-0000-0002-000000000162', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 19, '神啊，你必要杀戮恶人，所以你们好流人血的，离开我去吧！'),
('00000000-0000-0000-0002-000000000163', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 20, '因为他们说恶言顶撞你，你的仇敌也妄称你的名。'),
('00000000-0000-0000-0002-000000000164', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 21, '耶和华啊，恨恶你的，我岂不恨恶他们吗？攻击你的，我岂不憎嫌他们吗？'),
('00000000-0000-0000-0002-000000000165', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 139, 22, '我切切地恨恶他们，以他们为仇敌。'),
-- ==================== 新约经文数据 ====================
-- 新约 - 马太福音 5章（登山宝训）
('00000000-0000-0000-0002-000000000055', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 5, 1, '耶稣看见这许多的人，就上了山，既已坐下，门徒到他跟前来。'),
('00000000-0000-0000-0002-000000000056', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 5, 2, '他就开口教训他们，说：'),
('00000000-0000-0000-0002-000000000057', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 5, 3, '「虚心的人有福了，因为天国是他们的。」'),
('00000000-0000-0000-0002-000000000058', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 5, 4, '「哀恸的人有福了，因为他们必得安慰。」'),
('00000000-0000-0000-0002-000000000059', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 5, 5, '「温柔的人有福了，因为他们必承受地土。」'),
('00000000-0000-0000-0002-000000000060', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 5, 6, '「饥渴慕义的人有福了，因为他们必得饱足。」'),
('00000000-0000-0000-0002-000000000061', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 5, 7, '「怜恤人的人有福了，因为他们必蒙怜恤。」'),
('00000000-0000-0000-0002-000000000062', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 5, 8, '「清心的人有福了，因为他们必得见神。」'),
('00000000-0000-0000-0002-000000000063', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 5, 9, '「使人和睦的人有福了，因为他们必称为神的儿子。」'),
('00000000-0000-0000-0002-000000000064', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 5, 14, '「你们是世上的光。城造在山上，是不能隐藏的。」'),
('00000000-0000-0000-0002-000000000065', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 5, 16, '「你们的光也当这样照在人前，叫他们看见你们的好行为，便将荣耀归给你们在天上的父。」'),
-- 马太福音 6章
('00000000-0000-0000-0002-000000000066', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 6, 9, '「所以，你们祷告要这样说：我们在天上的父，愿人都尊你的名为圣。」'),
('00000000-0000-0000-0002-000000000067', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 6, 10, '「愿你的国降临。愿你的旨意行在地上，如同行在天上。」'),
('00000000-0000-0000-0002-000000000068', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 6, 33, '「你们要先求他的国和他的义，这些东西都要加给你们了。」'),
('00000000-0000-0000-0002-000000000069', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 6, 34, '「所以，不要为明天忧虑，因为明天自有明天的忧虑；一天的难处一天当就够了。」'),
-- 马太福音 11章
('00000000-0000-0000-0002-000000000070', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 11, 28, '「凡劳苦担重担的人，可以到我这里来，我就使你们得安息。」'),
('00000000-0000-0000-0002-000000000071', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 11, 29, '「我心里柔和谦卑，你们当负我的轭，学我的样式，这样，你们心里就必得享安息。」'),
-- 新约 - 路加福音 2章（耶稣诞生）
('00000000-0000-0000-0002-000000000072', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000042', 2, 8, '在伯利恒之野地里有牧羊的人，夜间按着更次看守羊群。'),
('00000000-0000-0000-0002-000000000073', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000042', 2, 9, '有主的使者站在他们旁边，主的荣光四面照着他们，牧羊的人就甚惧怕。'),
('00000000-0000-0000-0002-000000000074', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000042', 2, 10, '那天使对他们说：「不要惧怕，我报给你们大喜的信息，是关乎万民的。」'),
('00000000-0000-0000-0002-000000000075', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000042', 2, 11, '「因今天在大卫城里，为你们生了救主，就是主基督。」'),
('00000000-0000-0000-0002-000000000076', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000042', 2, 14, '「在至高之处荣耀归与神，在地上平安归与他所喜悦的人。」'),
-- 新约 - 约翰福音 3章
('00000000-0000-0000-0002-000000000077', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000043', 3, 16, '神爱世人，甚至将他的独生子赐给他们，叫一切信他的，不至灭亡，反得永生。'),
('00000000-0000-0000-0002-000000000078', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000043', 3, 17, '因为神差他的儿子降世，不是要定世人的罪，乃是要叫世人因他得救。'),
('00000000-0000-0000-0002-000000000079', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000043', 3, 18, '信他的人，不被定罪；不信的人，罪已经定了，因为他不信神独生子的名。'),
('00000000-0000-0000-0002-000000000080', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000043', 3, 19, '光来到世间，世人因自己的行为是恶的，不爱光，倒爱黑暗，定他们的罪就是在此。'),
('00000000-0000-0000-0002-000000000081', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000043', 3, 20, '凡作恶的便恨光，并不来就光，恐怕他的行为受责备。'),
('00000000-0000-0000-0002-000000000082', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000043', 3, 21, '但行真理的必来就光，要显明他所行的是靠神而行。'),
-- 约翰福音 14章
('00000000-0000-0000-0002-000000000083', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000043', 14, 6, '耶稣说：「我就是道路、真理、生命；若不借着我，没有人能到父那里去。」'),
('00000000-0000-0000-0002-000000000084', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000043', 14, 27, '「我留下平安给你们，我将我的平安赐给你们。我所赐的，不像世人所赐的。你们心里不要忧愁，也不要胆怯。」'),
-- 新约 - 罗马书 8章
('00000000-0000-0000-0002-000000000085', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000045', 8, 28, '我们晓得万事都互相效力，叫爱神的人得益处，就是按他旨意被召的人。'),
('00000000-0000-0000-0002-000000000086', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000045', 8, 31, '既是这样，还有什么说的呢？神若帮助我们，谁能敌挡我们呢？'),
('00000000-0000-0000-0002-000000000087', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000045', 8, 35, '谁能使我们与基督的爱隔绝呢？难道是患难吗？是困苦吗？是逼迫吗？是饥饿吗？是赤身露体吗？是危险吗？是刀剑吗？'),
('00000000-0000-0000-0002-000000000088', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000045', 8, 37, '然而，靠着爱我们的主，在这一切的事上已经得胜有余了。'),
('00000000-0000-0000-0002-000000000089', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000045', 8, 38, '因为我深信无论是死，是生，是天使，是掌权的，是有能的，是现在的事，是将来的事，'),
('00000000-0000-0000-0002-000000000090', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000045', 8, 39, '是高处的，是低处的，是别的受造之物，都不能叫我们与神的爱隔绝；这爱是在我们的主基督耶稣里的。'),
-- 新约 - 哥林多前书 13章（爱的颂歌）
('00000000-0000-0000-0002-000000000091', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000046', 13, 4, '爱是恒久忍耐，又有恩慈；爱是不嫉妒，爱是不自夸，不张狂，'),
('00000000-0000-0000-0002-000000000092', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000046', 13, 5, '不作害羞的事，不求自己的益处，不轻易发怒，不计算人的恶，'),
('00000000-0000-0000-0002-000000000093', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000046', 13, 6, '不喜欢不义，只喜欢真理；'),
('00000000-0000-0000-0002-000000000094', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000046', 13, 7, '凡事包容，凡事相信，凡事盼望，凡事忍耐；'),
('00000000-0000-0000-0002-000000000095', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000046', 13, 8, '爱是永不止息。'),
('00000000-0000-0000-0002-000000000096', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000046', 13, 13, '如今常存的有信，有望，有爱；这三样，其中最大的是爱。'),
-- 新约 - 以弗所书 2章
('00000000-0000-0000-0002-000000000097', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000049', 2, 8, '你们得救是本乎恩，也因着信；这并不是出于自己，乃是神所赐的；'),
('00000000-0000-0000-0002-000000000098', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000049', 2, 9, '也不是出于行为，免得有人自夸。'),
('00000000-0000-0000-0002-000000000099', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000049', 2, 10, '我们原是他的工作，在基督耶稣里造成的，为要叫我们行善，就是神所预备叫我们行的。'),
-- 新约 - 腓立比书 4章
('00000000-0000-0000-0002-000000000100', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000050', 4, 4, '你们要靠主常常喜乐；我再说，你们要喜乐。'),
('00000000-0000-0000-0002-000000000101', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000050', 4, 6, '应当一无挂虑，只要凡事借着祷告、祈求和感谢，将你们所要的告诉神。'),
('00000000-0000-0000-0002-000000000102', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000050', 4, 7, '神所赐出人意外的平安，必在基督耶稣里保守你们的心怀意念。'),
('00000000-0000-0000-0002-000000000103', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000050', 4, 13, '我靠着那加给我力量的，凡事都能作。'),
('00000000-0000-0000-0002-000000000104', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000050', 4, 19, '我的神必照他荣耀的丰富，在基督耶稣里使你们一切所需用的都充足。'),
-- 诗篇 22章（连续在诗篇23章之前，确保跨章连续）
('00000000-0000-0000-0002-000000000177', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 22, 1, '我的神，我的神！为什么离弃我？为什么远离不救我，不听我唉哼的言语？'),
('00000000-0000-0000-0002-000000000178', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 22, 2, '我的神啊，我白日呼求，你不应允；夜间呼求，并不住声。'),
('00000000-0000-0000-0002-000000000179', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 22, 3, '但你是圣洁的，是用以色列的赞美为宝座的。'),
('00000000-0000-0000-0002-000000000180', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 22, 4, '我们的祖宗倚靠你。他们倚靠你，你便解救他们。'),
('00000000-0000-0000-0002-000000000181', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 22, 5, '他们哀求你，便蒙解救；他们倚靠你，就不羞愧。'),
-- 诗篇 24章（连续在诗篇23章之后，确保跨章连续）
('00000000-0000-0000-0002-000000000182', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 24, 1, '地和其中所充满的，世界和住在其间的，都属耶和华。'),
('00000000-0000-0000-0002-000000000183', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 24, 2, '他把地建立在海上，安定在大水之上。'),
('00000000-0000-0000-0002-000000000184', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 24, 3, '谁能登耶和华的山？谁能站在他的圣所？'),
('00000000-0000-0000-0002-000000000185', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 24, 4, '就是手洁心清，不向虚妄，起誓不怀诡诈的人。'),
('00000000-0000-0000-0002-000000000186', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 24, 5, '他必蒙耶和华赐福，又蒙救他的神使他成义。'),
('00000000-0000-0000-0002-000000000187', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 24, 6, '这是寻求耶和华的族类，是寻求你面的雅各。'),
('00000000-0000-0000-0002-000000000188', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 24, 7, '众城门哪，你们要抬起头来！永久的门户，你们要被举起！那荣耀的王将要进来。'),
('00000000-0000-0000-0002-000000000189', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 24, 8, '荣耀的王是谁呢？就是有力有能的耶和华，在战场上有能的耶和华。'),
('00000000-0000-0000-0002-000000000190', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 24, 9, '众城门哪，你们要抬起头来！永久的门户，你们要把头抬起！那荣耀的王将要进来。'),
('00000000-0000-0000-0002-000000000191', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 24, 10, '荣耀的王是谁呢？万军之耶和华，他是荣耀的王！'),
-- 创世记 3章（连续在创世记2章之后）
('00000000-0000-0000-0002-000000000192', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000001', 3, 1, '耶和华神所造的，惟有蛇比田野一切的活物更狡猾。蛇对女人说：「神岂是真说不许你们吃园中所有树上的果子吗？」'),
('00000000-0000-0000-0002-000000000193', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000001', 3, 2, '女人对蛇说：「园中树上的果子，我们可以吃；'),
('00000000-0000-0000-0002-000000000194', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000001', 3, 3, '惟有园当中那棵树上的果子，神曾说：你们不可吃，也不可摸，免得你们死。」'),
('00000000-0000-0000-0002-000000000195', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000001', 3, 4, '蛇对女人说：「你们不一定死，'),
('00000000-0000-0000-0002-000000000196', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000001', 3, 5, '因为神知道，你们吃的日子眼睛就明亮了，你们便如神能知道善恶。」'),
-- 马太福音 7章（连续在马太福音6章之后，登山宝训结尾）
('00000000-0000-0000-0002-000000000197', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 7, 7, '「你们祈求，就给你们；寻找，就寻见；叩门，就给你们开门。」'),
('00000000-0000-0000-0002-000000000198', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 7, 8, '「因为凡祈求的，就得着；寻找的，就寻见；叩门的，就给他开门。」'),
('00000000-0000-0000-0002-000000000199', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 7, 12, '「所以，无论何事，你们愿意人怎样待你们，你们也要怎样待人，因为这就是律法和先知的道理。」'),
('00000000-0000-0000-0002-000000000200', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 7, 13, '「你们要进窄门。因为引到灭亡，那门是宽的，路是大的，进去的人也多；」'),
('00000000-0000-0000-0002-000000000201', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 7, 14, '「引到永生，那门是窄的，路是小的，找着的人也少。」');

