('00000000-0000-0000-0003-000000000112', '我主何谦卑', '诗韵赞美', NULL, 'https://faithchinesechurch.org/hymns/Poetic_Praise/%E6%88%91%E4%B8%BB%E4%BD%95%E8%B0%A6%E5%8D%91%20-%20%E9%9F%B3%E9%A2%91.m4a', 180, 'external', 'active'),
('00000000-0000-0000-0003-000000000113', '我的心，要欢呼！', '诗韵赞美', NULL, 'https://faithchinesechurch.org/hymns/Poetic_Praise/%E6%88%91%E7%9A%84%E5%BF%83%2C%20%E8%A6%81%E6%AC%A2%E5%91%BC%21%20-%20%E9%9F%B3%E9%A2%91.m4a', 180, 'external', 'active'),
