('00000000-0000-0000-0003-000000000115', '放声歌唱神的爱', '诗韵赞美', NULL, 'https://faithchinesechurch.org/hymns/Poetic_Praise/%E6%94%BE%E5%A3%B0%E6%AD%8C%E5%94%B1%E7%A5%9E%E7%9A%84%E7%88%B1%20-%20%E9%9F%B3%E9%A2%91.m4a', 180, 'external', 'active'),
('00000000-0000-0000-0003-000000000116', '最暖心的礼物', '诗韵赞美', NULL, 'https://faithchinesechurch.org/hymns/Poetic_Praise/%E6%9C%80%E6%9A%96%E5%BF%83%E7%9A%84%E7%A4%BC%E7%89%A9%20-%20%E9%9F%B3%E9%A2%91.mp3', 240, 'external', 'active'),
('00000000-0000-0000-0003-000000000117', '照你所求成全你', '诗韵赞美', NULL, 'https://faithchinesechurch.org/hymns/Poetic_Praise/%E7%85%A7%E4%BD%A0%E6%89%80%E6%B1%82%E6%88%90%E5%85%A8%E4%BD%A0%20-%20%E9%9F%B3%E9%A2%91.m4a', 180, 'external', 'active'),
('00000000-0000-0000-0003-000000000118', '神有最好的旨意', '诗韵赞美', NULL, 'https://faithchinesechurch.org/hymns/Poetic_Praise/%E7%A5%9E%E6%9C%89%E6%9C%80%E5%A5%BD%E7%9A%84%E6%97%A8%E6%84%8F%20-%20%E9%9F%B3%E9%A2%91.mp3', 240, 'external', 'active'),
('00000000-0000-0000-0003-000000000119', '神的教会永长存', '诗韵赞美', NULL, 'https://faithchinesechurch.org/hymns/Poetic_Praise/%E7%A5%9E%E7%9A%84%E6%95%99%E4%BC%9A%E6%B0%B8%E9%95%BF%E5%AD%98%20-%20%E9%9F%B3%E9%A2%91.m4a', 180, 'external', 'active'),
('00000000-0000-0000-0003-000000000120', '这是来自天父的爱', '诗韵赞美', NULL, 'https://faithchinesechurch.org/hymns/Poetic_Praise/%E8%BF%99%E6%98%AF%E6%9D%A5%E8%87%AA%E5%A4%A9%E7%88%B6%E7%9A%84%E7%88%B1%20-%20%E9%9F%B3%E9%A2%91.m4a', 180, 'external', 'active'),
('00000000-0000-0000-0003-000000000121', '颂扬赞美主为全能', '颂主圣诗', NULL, 'https://faithchinesechurch.org/hymns/Hymns_of_Praise/011%20%E9%A2%82%E6%89%AC%E8%B5%9E%E7%BE%8E%E4%B8%BB%E4%B8%BA%E5%85%A8%E8%83%BD%20-%20%E9%9F%B3%E9%A2%91.m4a', 180, 'external', 'active'),
('00000000-0000-0000-0003-000000000122', '祢的信实广大', '颂主圣诗', NULL, 'https://faithchinesechurch.org/hymns/Hymns_of_Praise/023%20%E7%A5%A2%E7%9A%84%E4%BF%A1%E5%AE%9E%E5%B9%BF%E5%A4%A7%20-%20%E9%9F%B3%E9%A2%91.m4a', 180, 'external', 'active'),
